import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        StringBuilder raw = new StringBuilder();
        String line;
        while ((line = br.readLine()) != null) {
            raw.append(line).append(' ');
        }
        // Replace escaped newlines ("\\n") with spaces to treat them as separators
        String all = raw.toString().replace("\\n", " ");
        StringTokenizer st = new StringTokenizer(all);
        if (!st.hasMoreTokens()) return;
        int T = Integer.parseInt(st.nextToken());
        StringBuilder out = new StringBuilder();
        for (int t = 0; t < T; t++) {
            if (!st.hasMoreTokens()) break;
            int N = Integer.parseInt(st.nextToken());
            int[] a = new int[N];
            Map<Integer, Integer> freq = new HashMap<>();
            for (int i = 0; i < N; i++) {
                int val = Integer.parseInt(st.nextToken());
                a[i] = val;
                freq.put(val, freq.getOrDefault(val, 0) + 1);
            }
            for (int i = 0; i < N; i++) {
                out.append(freq.get(a[i]));
                if (i + 1 < N) out.append(' ');
            }
            if (t + 1 < T) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

